import{_ as d,o as a,c as e,a5 as s}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"MOSFET 开关波形仿真","description":"","frontmatter":{"title":"MOSFET 开关波形仿真","date":"2026-07-02T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","chapterTitle":"仿真专题","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/MosfetSwitchingSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/MosfetSwitchingSim.vue","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/MosfetSwitchingSim.md","filePath":"content/motor/simulations/MosfetSwitchingSim.md","lastUpdated":null}'),o={name:"content/motor/simulations/MosfetSwitchingSim.md"};function r(i,t,n,l,h,c){return a(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="mosfet-开关波形仿真" tabindex="-1">MOSFET 开关波形仿真 <a class="header-anchor" href="#mosfet-开关波形仿真" aria-label="Permalink to &quot;MOSFET 开关波形仿真&quot;">​</a></h1><h4 id="mosfet-开关波形仿真-1" tabindex="-1">MOSFET 开关波形仿真 <a class="header-anchor" href="#mosfet-开关波形仿真-1" aria-label="Permalink to &quot;MOSFET 开关波形仿真&quot;">​</a></h4><h2 id="📖-教学说明-—-理解-mosfet-开关过程" tabindex="-1">📖 教学说明 — 理解 MOSFET 开关过程 <a class="header-anchor" href="#📖-教学说明-—-理解-mosfet-开关过程" aria-label="Permalink to &quot;📖 教学说明 — 理解 MOSFET 开关过程&quot;">​</a></h2><h5 id="开关过程-7-个阶段" tabindex="-1">开关过程 7 个阶段 <a class="header-anchor" href="#开关过程-7-个阶段" aria-label="Permalink to &quot;开关过程 7 个阶段&quot;">​</a></h5><table tabindex="0"><thead><tr><th>阶段</th><th>名称</th><th>Vgs 变化</th><th>Vds 变化</th><th>物理过程</th></tr></thead><tbody><tr><td>1</td><td>td(on) 开通延迟</td><td>0 → Vth</td><td>= Vbus</td><td>栅极电压通过 Rg 对 Ciss 充电，达到阈值前 MOSFET 不导通</td></tr><tr><td>2</td><td>tr 上升时间</td><td>= Vplateau</td><td>Vbus → Rdson·Id</td><td><strong>米勒平台</strong>：Vgs 被钳位，栅极电流全部用于对 Cgd 放电，Vds 快速下降</td></tr><tr><td>3</td><td>尾部充电</td><td>Vplateau → Vdrive</td><td>≈ Rdson·Id</td><td>米勒效应结束，Vgs 继续上升至驱动电压，沟道完全增强</td></tr><tr><td>4</td><td>导通保持</td><td>= Vdrive</td><td>= Rdson·Id</td><td>MOSFET 完全导通，Vds 很小（导通压降）</td></tr><tr><td>5</td><td>td(off) 关断延迟</td><td>Vdrive → Vplateau</td><td>≈ Rdson·Id</td><td>Ciss 通过 Rg 放电至米勒平台电压</td></tr><tr><td>6</td><td>tf 下降时间</td><td>= Vplateau</td><td>Rdson·Id → Vbus</td><td><strong>米勒平台</strong>：Vgs 再次被钳位，Cgd 充电使 Vds 上升</td></tr><tr><td>7</td><td>尾部放电</td><td>Vplateau → 0</td><td>= Vbus</td><td>Ciss 完全放电，沟道完全关断</td></tr></tbody></table><h5 id="米勒平台原理" tabindex="-1">米勒平台原理 <a class="header-anchor" href="#米勒平台原理" aria-label="Permalink to &quot;米勒平台原理&quot;">​</a></h5><p>当 Vgs 达到 <strong>Vplateau = Vth + Id/gm</strong> 时，MOSFET 进入饱和区。此时栅极驱动电流不再给 Cgs 充电，而是<strong>全部用于对米勒电容 Cgd 充放电</strong>。Vgs 被&quot;钳位&quot;在 Vplateau，形成波形中的平坦区域（黄色高亮区）。</p><p><strong>关键公式</strong>：米勒平台持续时间 <code>t_plateau = Rg · Qgd / (Vdrive - Vplateau)</code>，即 tr 和 tf 的长度。</p><h5 id="参数影响" tabindex="-1">参数影响 <a class="header-anchor" href="#参数影响" aria-label="Permalink to &quot;参数影响&quot;">​</a></h5><ul><li><p><strong>Rg ↑</strong> → 开关速度 ↓ → tr, tf 增大 → <strong>开关损耗 ↑</strong>，但 EMI ↓（di/dt 和 dv/dt 降低）</p></li><li><p><strong>Vdrive ↑</strong> → 开关速度 ↑ → tr, tf 减小 → 开关损耗 ↓，但需要确保 Vgs 不超过 ±20V 额定值</p></li><li><p><strong>Ciss ↑</strong>（大功率 MOSFET）→ 充放电时间 ↑ → 需要更大的栅极驱动电流</p></li></ul><h5 id="开关损耗估算" tabindex="-1">开关损耗估算 <a class="header-anchor" href="#开关损耗估算" aria-label="Permalink to &quot;开关损耗估算&quot;">​</a></h5><p>单次开关能量（硬开关）：</p><p><code>Esw ≈ 0.5 · Vbus · Id · (tr + tf)</code></p><p>开关损耗功率（PWM 频率 fsw）：</p><p><code>Psw = Esw · fsw</code></p><p><strong>示例</strong>：Vbus=48V, Id=10A, tr+tf=50ns, fsw=20kHz → Esw≈12μJ, Psw≈0.24W。若 tr+tf 增大到 200ns（Rg 过大），Psw 升至 ≈1W，散热需求显著增加。</p>',16)])])}const g=d(o,[["render",r]]);export{p as __pageData,g as default};
